attempt_2_commands:
awk_script='#!/usr/bin/awk -f
BEGIN { found=0 }
{
  # Remove leading whitespace
  line = $0
  sub(/^[ \t]+/, "", line)

  # Check if line contains minlen (with optional leading # and whitespace)
  if (line ~ /^[[:space:]]*#[[:space:]]*minlen[[:space:]]*=/ || line ~ /^[[:space:]]*minlen[[:space:]]*=/) {
    print "minlen = 14"
    found=1
  } else {
    print $0
  }
}
END { if (!found) print "minlen = 14" }' && echo "$awk_script" > /tmp/set_minlen.awk; awk -f /tmp/set_minlen.awk /etc/security/pwquality.conf > /tmp/pwquality.conf.tmp && mv /tmp/pwquality.conf.tmp /etc/security/pwquality.conf; ls -1 /etc/security/pwquality.conf.d/*.conf 2>/dev/null || echo "no files"; grep -E "^[[:space:]]*minlen[[:space:]]*=" /etc/security/pwquality.conf; awk '/^[[:space:]]*minlen[[:space:]]*=/ {print $3}' /etc/security/pwquality.conf | sort -u; echo "Remediation complete: minlen set to 14 in /etc/security/pwquality.conf"; awk_script='#!/usr/bin/awk -f
{
  # Check if line contains minlen parameter (with optional leading # and whitespace)
  if ($0 ~ /^[[:space:]]*#[[:space:]]*minlen[[:space:]]*=/ || $0 ~ /^[[:space:]]*minlen[[:space:]]*=/) {
    print "minlen = 14"
    found = 1
  } else {
    print $0
  }
}
END { if (!found) print "minlen = 14" }' && echo "$awk_script" > /tmp/set_minlen.awk; awk -f /tmp/set_minlen.awk /etc/security/pwquality.conf > /tmp/pwquality.conf.tmp && mv /tmp/pwquality.conf.tmp /etc/security/pwquality.conf; ls -1 /etc/security/pwquality.conf.d/*.conf 2>/dev/null || echo "no files"; grep -E "^[[:space:]]*minlen[[:space:]]*=" /etc/security/pwquality.conf; awk -F= '/^[[:space:]]*minlen[[:space:]]*=/ {gsub(/^[[:space:]]+|[[:space:]]+$/, "", $2); print $2}' /etc/security/pwquality.conf | sort -u
